@tailwind base;
@tailwind components;
@tailwind utilities;

@layer utilities {
  .text-balance {
    text-wrap: balance;
  }
}

@layer base {
  :root {
    --background: 210 40% 98%;
    --foreground: 200 43% 20%;
    --card: 0 0% 100%;
    --card-foreground: 200 43% 20%;
    --popover: 0 0% 100%;
    --popover-foreground: 200 43% 20%;
    --primary: 198 73% 29%;
    --primary-foreground: 0 0% 100%;
    --secondary: 195 25% 92%;
    --secondary-foreground: 200 43% 20%;
    --muted: 210 15% 93%;
    --muted-foreground: 200 10% 50%;
    --accent: 195 25% 92%;
    --accent-foreground: 200 43% 20%;
    --destructive: 0 84.2% 60.2%;
    --destructive-foreground: 0 0% 98%;
    --border: 210 15% 90%;
    --input: 210 15% 90%;
    --ring: 200 43% 20%;
    --radius: 0.75rem;
  }
}

@layer base {
  * {
    @apply border-border;
  }
  html,
  body {
    @apply bg-background text-foreground;
    max-width: 100vw;
    overflow-x: hidden;
  }
}

