  onChange,
}: {
  tabela: TabelaPrecos
  onChange: (t: TabelaPrecos) => void
}) {
  const setFaixa = (idx: number, field: keyof FaixaPreco, val: string) => {
    const faixas = tabela.faixas.map((f, i) => (i === idx ? { ...f, [field]: val } : f))
    onChange({ ...tabela, faixas })
  }

  const setAptos = (field: keyof PrecosImovel, val: string) =>
    onChange({ ...tabela, aptosEComerciais: { ...tabela.aptosEComerciais, [field]: val } })

  const setCasas = (field: keyof PrecosImovel, val: string) =>
    onChange({ ...tabela, casas: { ...tabela.casas, [field]: val } })

  return (
    <div className="space-y-6">
      {/* Faixas de preço */}
      <div>
        <h3 className="text-base font-semibold text-gray-900 mb-3">Tabela de preços</h3>
        <div className="space-y-2">
          {tabela.faixas.map((faixa, idx) => (
            <div key={idx} className="grid grid-cols-3 gap-3">
              <div className="space-y-1">
                <label className="text-xs text-gray-500">De (m²)</label>
                <AdminInput
                  variant="form"
                  type="number"
                  value={faixa.de}
                  onChange={(e) => setFaixa(idx, "de", e.target.value)}
                />
              </div>
              <div className="space-y-1">
                <label className="text-xs text-gray-500">Até (m²)</label>
                <AdminInput
                  variant="form"
                  type="number"
                  value={faixa.ate}
                  onChange={(e) => setFaixa(idx, "ate", e.target.value)}
                />
              </div>
              <div className="space-y-1">
                <label className="text-xs text-gray-500">Preço (R$)</label>
                <AdminInput
                  variant="form"
                  type="number"
                  value={faixa.preco}
                  onChange={(e) => setFaixa(idx, "preco", e.target.value)}
                />
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Para imóveis acima de 120m² */}
      <div>
        <p className="text-xs font-semibold text-gray-500 uppercase tracking-wide mb-3">
          Para imóveis acima de 120m²
        </p>
        <div className="grid grid-cols-2 gap-6">
          {/* Apartamentos + Imóveis Comerciais */}
          <div className="space-y-3">
            <div>
              <p className="text-sm font-medium text-gray-800">Apartamentos</p>
              <p className="text-sm font-medium text-gray-800 mt-1">Imóveis comerciais</p>
              <ul className="text-sm text-gray-400 ml-3 mt-0.5 space-y-0.5">
                <li>• Sala</li>
                <li>• Galpão</li>
                <li>• Loja</li>
              </ul>
            </div>
            <div className="space-y-1">
              <label className="text-xs text-gray-500">Sem mobília (Preço por M²)</label>
              <AdminInput
                variant="form"
                type="number"
                value={tabela.aptosEComerciais.semMobilia}
                onChange={(e) => setAptos("semMobilia", e.target.value)}
              />
            </div>
            <div className="space-y-1">
              <label className="text-xs text-gray-500">Semi-mobiliado (Preço por M²)</label>
              <AdminInput
                variant="form"
                type="number"
                value={tabela.aptosEComerciais.semiMobiliado}
                onChange={(e) => setAptos("semiMobiliado", e.target.value)}
              />
            </div>
            <div className="space-y-1">
              <label className="text-xs text-gray-500">Mobiliado (Preço por M²)</label>
              <AdminInput
                variant="form"
                type="number"
                value={tabela.aptosEComerciais.mobiliado}
                onChange={(e) => setAptos("mobiliado", e.target.value)}
              />
            </div>
          </div>

          {/* Casas */}
          <div className="space-y-3">
            <p className="text-sm font-medium text-gray-800">Casas</p>
            <div className="space-y-1">
              <label className="text-xs text-gray-500">Sem mobília (Preço por M²)</label>
              <AdminInput
                variant="form"
                type="number"
                value={tabela.casas.semMobilia}
                onChange={(e) => setCasas("semMobilia", e.target.value)}
              />
            </div>
            <div className="space-y-1">
              <label className="text-xs text-gray-500">Semi-mobiliado (Preço por M²)</label>
              <AdminInput
                variant="form"
                type="number"
                value={tabela.casas.semiMobiliado}
                onChange={(e) => setCasas("semiMobiliado", e.target.value)}
              />
            </div>
            <div className="space-y-1">
              <label className="text-xs text-gray-500">Mobiliado (Preço por M²)</label>
              <AdminInput
                variant="form"
                type="number"
                value={tabela.casas.mobiliado}
                onChange={(e) => setCasas("mobiliado", e.target.value)}
              />
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

// ─── Page ─────────────────────────────────────────────────────────────────────
export default function BackofficeClientesPage() {
  const [aba, setAba] = useState<Aba>("clientes")

  // Filtros
  const [busca, setBusca] = useState("")
  const [filtroTipo, setFiltroTipo] = useState("all")
  const [filtroFinanceiro, setFiltroFinanceiro] = useState("all")

  // Seleção em lote
  const [selecionados, setSelecionados] = useState<Set<string>>(new Set())

  // Modal novo cliente
  const [showModalNovoCliente, setShowModalNovoCliente] = useState(false)
  const [novoCliente, setNovoCliente] = useState({
    tipo: "pf", nome: "", documento: "", email: "",
    estado: "", unidade: "", cobranca: "avulso", enviarEmail: true,
  })

  // Modal editar cliente
  const [clienteEditando, setClienteEditando] = useState<Cliente | null>(null)
  const [dadosEdicao, setDadosEdicao] = useState({
    nome: "", documento: "", email: "", telefone: "", cidade: "",
    tipo: "pf", status: "ativo" as ClienteStatus,
  })

  const abrirEdicao = (c: Cliente) => {
    setDadosEdicao({
      nome: c.nome, documento: c.documento, email: c.email,
      telefone: c.telefone, cidade: c.cidade,
      tipo: c.tipo, status: c.status,
    })
    setClienteEditando(c)
  }

  const handleSalvarEdicao = () => setClienteEditando(null)

  // ─── Condições Comerciais ────────────────────────────────────────────────────
  const [buscaCondicao, setBuscaCondicao] = useState("")
  const [clienteSelecionado, setClienteSelecionado] = useState<Cliente | null>(null)
  const [showModalCondicao, setShowModalCondicao] = useState(false)
  const [novaCondicao, setNovaCondicao] = useState({
    tipoCondicao: "funcoes_pj" as Condicao["tipoCondicao"],
    desconto: 0,
    prazo: 7,
    vigenciaInicio: "",
    vigenciaFim: "",
  })

  const clientesBuscados = useMemo(() => {
    if (!buscaCondicao.trim()) return []
    const termo = buscaCondicao.toLowerCase()
    return CLIENTES.filter((c) =>
      [c.nome, c.documento, c.email].some((v) => v.toLowerCase().includes(termo))
    ).slice(0, 5)
  }, [buscaCondicao])

  const handleSelecionarCliente = (cliente: Cliente) => {
    setClienteSelecionado(cliente)
    setBuscaCondicao("")
    setNovaCondicao({
      tipoCondicao: cliente.tipo === "pf" ? "funcoes_pj" : "desconto",
      desconto: cliente.tipo === "pj" ? 10 : 0,
      prazo: 7,
      vigenciaInicio: new Date().toLocaleDateString("pt-BR"),
      vigenciaFim: "",
    })
    setShowModalCondicao(true)
  }

  const handleSalvarCondicao = () => {
    setShowModalCondicao(false)
    setClienteSelecionado(null)
    setNovaCondicao({ tipoCondicao: "funcoes_pj", desconto: 0, prazo: 7, vigenciaInicio: "", vigenciaFim: "" })
  }

  const handleCancelarCondicao = () => {
    setShowModalCondicao(false)
    setClienteSelecionado(null)
  }

  const isCondicaoFormValid = novaCondicao.vigenciaFim !== ""

  // Filtros condições
  const [buscaListaCondicoes, setBuscaListaCondicoes] = useState("")
  const [filtroCondicaoTipo, setFiltroCondicaoTipo] = useState("all")
  const [filtroCondicaoDesconto, setFiltroCondicaoDesconto] = useState("all")
  const [filtroCondicaoPrazo, setFiltroCondicaoPrazo] = useState("all")
  const [filtroCondicaoVigencia, setFiltroCondicaoVigencia] = useState("all")
  const [filtroCondicaoStatus, setFiltroCondicaoStatus] = useState("all")

  const condicoesFiltradas = useMemo(() => {
    return CONDICOES.filter((c) => {
      const matchBusca = !buscaListaCondicoes || c.clienteNome.toLowerCase().includes(buscaListaCondicoes.toLowerCase())
      const matchTipo = filtroCondicaoTipo === "all" || c.tipoCondicao === filtroCondicaoTipo
      const matchDesconto = filtroCondicaoDesconto === "all"
        || (filtroCondicaoDesconto === "com" && c.desconto > 0)
        || (filtroCondicaoDesconto === "sem" && c.desconto === 0)
      const matchPrazo = filtroCondicaoPrazo === "all"
        || (filtroCondicaoPrazo === "curto" && c.prazo <= 15)
        || (filtroCondicaoPrazo === "medio" && c.prazo > 15 && c.prazo <= 30)
        || (filtroCondicaoPrazo === "longo" && c.prazo > 30)
      const hoje = new Date()
      const [d, m, y] = c.vigenciaFim.split("/").map(Number)
      const fimDate = new Date(y, m - 1, d)
      const matchVigencia = filtroCondicaoVigencia === "all"
        || (filtroCondicaoVigencia === "vence30" && fimDate > hoje && (fimDate.getTime() - hoje.getTime()) / 86400000 <= 30)
        || (filtroCondicaoVigencia === "vigente" && fimDate >= hoje)
        || (filtroCondicaoVigencia === "expirado" && fimDate < hoje)
      const matchStatus = filtroCondicaoStatus === "all" || c.status === filtroCondicaoStatus
      return matchBusca && matchTipo && matchDesconto && matchPrazo && matchVigencia && matchStatus
    })
  }, [buscaListaCondicoes, filtroCondicaoTipo, filtroCondicaoDesconto, filtroCondicaoPrazo, filtroCondicaoVigencia, filtroCondicaoStatus])

  // ─── Tabela de Preços por Cliente ────────────────────────────────────────────
  const [showModalTabelaPrecos, setShowModalTabelaPrecos] = useState(false)
  const [condicaoTabela, setCondicaoTabela] = useState<Condicao | null>(null)
  const [tabelaPrecos, setTabelaPrecos] = useState<TabelaPrecos>({
    tipoConta: "pj",
    ...PRECOS_PADRAO_PJ,
    faixas: PRECOS_PADRAO_PJ.faixas.map((f) => ({ ...f })),
  })

  const abrirTabelaPrecos = (cond: Condicao) => {
    const defaults = cond.clienteTipo === "pj" ? PRECOS_PADRAO_PJ : PRECOS_PADRAO_PF
    setTabelaPrecos({
      tipoConta: cond.clienteTipo,
      faixas: defaults.faixas.map((f) => ({ ...f })),
      aptosEComerciais: { ...defaults.aptosEComerciais },
      casas: { ...defaults.casas },
    })
    setCondicaoTabela(cond)
    setShowModalTabelaPrecos(true)
  }

  // ─── Config Padrão ───────────────────────────────────────────────────────────
  const [configPF, setConfigPF] = useState<TabelaPrecos>({
    tipoConta: "pf",
    faixas: PRECOS_PADRAO_PF.faixas.map((f) => ({ ...f })),
    aptosEComerciais: { ...PRECOS_PADRAO_PF.aptosEComerciais },
    casas: { ...PRECOS_PADRAO_PF.casas },
  })

  const [configPJ, setConfigPJ] = useState<TabelaPrecos>({
    tipoConta: "pj",
    faixas: PRECOS_PADRAO_PJ.faixas.map((f) => ({ ...f })),
    aptosEComerciais: { ...PRECOS_PADRAO_PJ.aptosEComerciais },
    casas: { ...PRECOS_PADRAO_PJ.casas },
  })

  // ─── Form validation ─────────────────────────────────────────────────────────
  const isFormValid = novoCliente.nome && novoCliente.documento && novoCliente.email && novoCliente.estado && novoCliente.unidade

  const handleCriarCliente = () => {
    setShowModalNovoCliente(false)
    setNovoCliente({ tipo: "pf", nome: "", documento: "", email: "", estado: "", unidade: "", cobranca: "avulso", enviarEmail: true })
  }

  // Dados filtrados
  const clientesFiltrados = useMemo(() => {
    const termo = busca.toLowerCase()
    return CLIENTES.filter((c) => {
      const matchBusca = !termo || [c.nome, c.documento, c.email, c.cidade].some((v) => v.toLowerCase().includes(termo))
      const matchTipo = filtroTipo === "all" || c.tipo === filtroTipo
      const matchFin  = filtroFinanceiro === "all" || c.statusFinanceiro === filtroFinanceiro
      return matchBusca && matchTipo && matchFin
    })
  }, [busca, filtroTipo, filtroFinanceiro])

  const todosSelected = clientesFiltrados.length > 0 && clientesFiltrados.every((c) => selecionados.has(c.id))

  const toggleAll = () => {
    if (todosSelected) {
      setSelecionados((prev) => { const next = new Set(prev); clientesFiltrados.forEach((c) => next.delete(c.id)); return next })
    } else {
      setSelecionados((prev) => { const next = new Set(prev); clientesFiltrados.forEach((c) => next.add(c.id)); return next })
    }
  }

  const toggleOne = (id: string) => {
    setSelecionados((prev) => { const next = new Set(prev); next.has(id) ? next.delete(id) : next.add(id); return next })
  }

  // ─── Colunas Clientes ────────────────────────────────────────────────────────
  const colunasClientes: ColumnDef<Cliente>[] = [
    {
      id: "select",
      header: () => <Checkbox checked={todosSelected} onCheckedChange={toggleAll} className="cursor-pointer" />,
      cell: ({ row }) => <Checkbox checked={selecionados.has(row.original.id)} onCheckedChange={() => toggleOne(row.original.id)} className="cursor-pointer" />,
      size: 40,
    },
    {
      accessorKey: "nome",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Cliente" />,
      cell: ({ row }) => {
        const c = row.original
        return (
          <div className="flex items-center gap-3">
            <div className="h-9 w-9 rounded-full bg-[#0B7A8F]/10 flex items-center justify-center shrink-0">
              {c.tipo === "pj" ? <Building2 size={15} className="text-[#0B7A8F]" /> : <User size={15} className="text-[#0B7A8F]" />}
            </div>
            <div className="min-w-0">
              <div className="flex items-center gap-2">
                <p className="text-sm font-semibold text-gray-800 truncate">{c.nome}</p>
                <span className="text-xs font-medium px-1.5 py-0.5 rounded bg-gray-100 text-gray-500 uppercase tracking-wide">
                  {c.tipo === "pf" ? "PF" : "PJ"}
                </span>
              </div>
              <div className="flex flex-wrap items-center gap-x-3 gap-y-0.5 mt-0.5">
                <span className="text-xs text-gray-400">{c.documento}</span>
                <span className="flex items-center gap-1 text-xs text-gray-400"><Mail size={11} />{c.email}</span>
                <span className="flex items-center gap-1 text-xs text-gray-400"><MapPin size={11} />{c.cidade}</span>
              </div>
            </div>
          </div>
        )
      },
    },
    {
      accessorKey: "statusFinanceiro",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Financeiro" />,
      cell: ({ row }) => {
        const f = financeiroConfig[row.original.statusFinanceiro]
        return <span className={`inline-flex items-center text-xs font-medium px-2.5 py-1 rounded-full ${f.className}`}>{f.label}</span>
      },
    },
    {
      accessorKey: "status",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Status" />,
      cell: ({ row }) => {
        const s = statusConfig[row.original.status]
        const Icon = s.icon
        return (
          <span className={`inline-flex items-center gap-1.5 text-xs font-medium px-2.5 py-1 rounded-full ${s.className}`}>
            <Icon size={11} />{s.label}
          </span>
        )
      },
    },
    {
      accessorKey: "desde",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Desde" />,
      cell: ({ row }) => <span className="text-xs text-gray-400">{row.original.desde}</span>,
    },
    {
      id: "acoes",
      header: "",
      cell: ({ row }) => (
        <div className="flex justify-end">
          <button
            onClick={() => abrirEdicao(row.original)}
            className="p-1.5 text-gray-500 hover:text-[#0B7A8F] transition-colors rounded hover:bg-gray-100"
            title="Editar cliente"
          >
            <Pencil size={16} />
          </button>
        </div>
      ),
      size: 80,
    },
  ]

  // ─── Colunas Condições ────────────────────────────────────────────────────────
  const colunasCondicoes: ColumnDef<Condicao>[] = [
    {
      accessorKey: "clienteNome",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Cliente" />,
      cell: ({ row }) => (
        <div className="flex items-center gap-3">
          <div className="h-9 w-9 rounded-full bg-[#0B7A8F]/10 flex items-center justify-center shrink-0">
            {row.original.clienteTipo === "pj" ? <Building2 size={15} className="text-[#0B7A8F]" /> : <User size={15} className="text-[#0B7A8F]" />}
          </div>
          <div>
            <p className="text-sm font-medium text-gray-800">{row.original.clienteNome}</p>
            <span className="text-xs text-gray-400 uppercase">{row.original.clienteTipo === "pf" ? "Pessoa Física" : "Pessoa Jurídica"}</span>
          </div>
        </div>
      ),
    },
    {
      accessorKey: "tipoCondicao",
      header: "Condição",
      cell: ({ row }) => {
        const cfg = tipoCondicaoConfig[row.original.tipoCondicao]
        return <span className={`text-xs font-medium px-2.5 py-1 rounded-full ${cfg.className}`}>{cfg.label}</span>
      },
    },
    {
      accessorKey: "desconto",
      header: "Desconto",
      cell: ({ row }) => (
        <span className="text-sm font-semibold text-gray-800">
          {row.original.desconto > 0 ? `${row.original.desconto}%` : "—"}
