    {
      id: "acoes",
      header: "",
      cell: ({ row }) => (
        <div className="flex justify-end">
          <button
            onClick={() => abrirTabelaPrecos(row.original)}
            className="p-1.5 text-gray-500 hover:text-[#0B7A8F] transition-colors rounded hover:bg-gray-100"
