                <label className="text-xs font-medium text-gray-500">Financeiro</label>
                <Select value={filtroFinanceiro} onValueChange={setFiltroFinanceiro}>
                  <SelectTrigger className="h-10 w-36 px-3"><SelectValue placeholder="Todos" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">Todos</SelectItem>
                    <SelectItem value="em_dia">Em dia</SelectItem>
                    <SelectItem value="vencido">Vencido</SelectItem>
                    <SelectItem value="bloqueado">Bloqueado</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="flex flex-col justify-end">
                <AdminButton variant="primary" icon={<Plus size={16} />} onClick={() => setShowModalNovoCliente(true)}>
                  Novo Cliente
                </AdminButton>
              </div>
            </div>

            <div className="flex items-center gap-2">
              <span className="text-sm text-gray-500">
                <span className="font-semibold text-gray-800">{clientesFiltrados.length}</span>
                {clientesFiltrados.length !== CLIENTES.length && (
                  <> de <span className="font-semibold text-gray-800">{CLIENTES.length}</span></>
