"use client"

import { use } from "react"
import { useRouter } from "next/navigation"
import { AdminDashboardLayout } from "@/components/admin/admin-dashboard-layout"
import { AdminButton } from "@/components/admin/admin-button"
import { getVistoriaById, ETAPAS } from "@/lib/mock-vistorias"
import {
  MapPin, Tag, CalendarClock, User,
  MessageSquare, Download, Check,
} from "lucide-react"

export default function VistoriaDetalhePage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = use(params)
  const router = useRouter()
  const vistoria = getVistoriaById(id)

  if (!vistoria) {
    return (
      <AdminDashboardLayout profile="cliente" title="Vistoria não encontrada">
        <div className="flex flex-col items-center justify-center py-20">
          <p className="text-gray-500 mb-4">Vistoria não encontrada.</p>
          <AdminButton variant="outline" onClick={() => router.back()}>Voltar</AdminButton>
        </div>
      </AdminDashboardLayout>
    )
  }

  return (
    <AdminDashboardLayout
      profile="cliente"
      title={vistoria.id}
      breadcrumbs={[
        { label: "Vistorias", href: "/admin/cliente/vistorias/andamento" },
        {
          label: vistoria.status === "Pedido"
            ? "Vistorias Solicitadas"
            : vistoria.status === "Em andamento"
              ? "Vistorias em Andamento"
              : "Vistorias Concluídas",
          href:
            vistoria.status === "Pedido"
              ? "/admin/cliente/vistorias/pedidos"
              : vistoria.status === "Em andamento"
                ? "/admin/cliente/vistorias/andamento"
                : "/admin/cliente/vistorias/concluidas",
        },
      ]}
    >

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Coluna principal */}
        <div className="lg:col-span-2 space-y-6">
          {/* Dados principais */}
          <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
            <div className="flex items-center gap-3 mb-5">
              <h2 className="text-base font-bold text-gray-900">Informações da Vistoria</h2>
              <span className={`px-2 py-0.5 rounded-full text-xs font-semibold ${vistoria.statusColor}`}>
                {vistoria.status}
              </span>

