"use client"

import { useState } from "react"
import { AdminDashboardLayout } from "@/components/admin/admin-dashboard-layout"
import { AdminTable } from "@/components/admin/admin-table"
import { AdminButton } from "@/components/admin/admin-button"
import { AdminModal, AdminModalHeader, AdminModalBody, AdminModalFooter } from "@/components/admin/admin-modal"
import { type ColumnDef } from "@tanstack/react-table"
import { AdminTableSortHeader } from "@/components/admin/admin-table"
import { Gift, Pencil, CheckCircle2 } from "lucide-react"

// ─── Tipos ─────────────────────────────────────────────────────────────────
type Nivel = "junior" | "pleno" | "senior"

interface Vistoriador {
  id: string
  nome: string
  nivel: Nivel
  telefone: string
  vistorias: number       // vistorias no mês
  bonusDisponibilidade: number // valor do bônus de disponibilidade (editável)
  ativo: boolean
}

// ─── Mock ───────────────────────────────────────────────────────────────────
const VISTORIADORES_MOCK: Vistoriador[] = [
  { id: "vis-001", nome: "Ricardo Souza",   nivel: "pleno",  telefone: "(11) 99001-1111", vistorias: 18, bonusDisponibilidade: 150, ativo: true },
  { id: "vis-002", nome: "Juliana Costa",   nivel: "senior", telefone: "(11) 99001-2222", vistorias: 22, bonusDisponibilidade: 200, ativo: true },
  { id: "vis-003", nome: "Paulo Rocha",     nivel: "junior", telefone: "(11) 99001-3333", vistorias: 11, bonusDisponibilidade: 100, ativo: true },
  { id: "vis-004", nome: "Carlos Mendonça", nivel: "pleno",  telefone: "(21) 99002-4444", vistorias: 15, bonusDisponibilidade: 150, ativo: true },
  { id: "vis-005", nome: "Ana Ferreira",    nivel: "senior", telefone: "(21) 99002-5555", vistorias: 20, bonusDisponibilidade: 200, ativo: false },
  { id: "vis-006", nome: "Roberto Lima",    nivel: "junior", telefone: "(21) 99002-6666", vistorias:  8, bonusDisponibilidade: 100, ativo: true },
  { id: "vis-007", nome: "Patrícia Souza",  nivel: "pleno",  telefone: "(11) 99001-7777", vistorias: 16, bonusDisponibilidade: 150, ativo: true },
]

const NIVEL_LABEL: Record<Nivel, string> = { junior: "Júnior", pleno: "Pleno", senior: "Sênior" }
const NIVEL_COLOR: Record<Nivel, string> = {
  junior: "bg-gray-100 text-gray-600",
  pleno:  "bg-blue-50 text-blue-700",
  senior: "bg-purple-50 text-purple-700",
}

const fmt = (v: number) =>
  new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL" }).format(v)

// ─── Página ─────────────────────────────────────────────────────────────────
export default function VistoriadoresPage() {
  const [vistoriadores, setVistoriadores] = useState<Vistoriador[]>(VISTORIADORES_MOCK)
  const [editando, setEditando] = useState<Vistoriador | null>(null)
  const [bonusInput, setBonusInput] = useState("")
  const [salvou, setSalvou] = useState(false)

  const abrirEdicao = (v: Vistoriador) => {
    setEditando(v)
    setBonusInput(String(v.bonusDisponibilidade))
    setSalvou(false)
  }

  const salvarBonus = () => {
    if (!editando) return
    const valor = parseFloat(bonusInput.replace(",", "."))
    if (isNaN(valor) || valor < 0) return
    setVistoriadores((prev) =>
      prev.map((v) => v.id === editando.id ? { ...v, bonusDisponibilidade: valor } : v)
    )
    setSalvou(true)
    setTimeout(() => {
      setSalvou(false)
      setEditando(null)
    }, 800)
  }

  const columns: ColumnDef<Vistoriador, unknown>[] = [
    {
      accessorKey: "nome",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Nome" />,
      cell: ({ row }) => (
        <div>
          <p className="text-sm font-medium text-gray-900">{row.original.nome}</p>
          <p className="text-xs text-gray-400">{row.original.telefone}</p>
        </div>
      ),
    },
    {
      accessorKey: "nivel",
      header: "Nível",
      cell: ({ row }) => (
        <span className={`px-2.5 py-1 rounded-full text-xs font-semibold ${NIVEL_COLOR[row.original.nivel]}`}>
          {NIVEL_LABEL[row.original.nivel]}
        </span>
      ),
    },
    {
      accessorKey: "vistorias",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Vistorias (mês)" />,
      cell: ({ row }) => (
        <span className="text-sm text-gray-700 font-medium">{row.original.vistorias}</span>
      ),
    },
    {
      accessorKey: "bonusDisponibilidade",
      header: ({ column }) => <AdminTableSortHeader column={column} label="Bônus de Disponib." />,
      cell: ({ row }) => (
        <div className="flex items-center gap-1.5">
          <Gift size={13} className="text-emerald-500" />
          <span className="text-sm font-semibold text-emerald-700">
            {fmt(row.original.bonusDisponibilidade)}
          </span>
        </div>
      ),
    },
    {
      id: "status",
      header: "Status",
      cell: ({ row }) => (
        row.original.ativo
          ? <span className="px-2.5 py-1 rounded-full text-xs font-semibold bg-green-50 text-green-700">Ativo</span>
          : <span className="px-2.5 py-1 rounded-full text-xs font-semibold bg-gray-100 text-gray-500">Inativo</span>
      ),
    },
    {
      id: "acoes",
      header: "",
      cell: ({ row }) => (
        <AdminButton
          variant="outline"
          size="sm"
          icon={<Pencil size={13} />}
          onClick={() => abrirEdicao(row.original)}
        >
          Editar bônus
        </AdminButton>
      ),
    },
  ]

  return (
    <AdminDashboardLayout
      profile="backoffice"
      title="Vistoriadores"
      breadcrumbs={[{ label: "Configurações", href: "/admin/backoffice/config" }]}
    >
      {/* Header com descrição */}
      <div className="mb-6">
        <p className="text-sm text-gray-500">
          Gerencie os vistoriadores cadastrados e configure o{" "}
          <strong>Bônus de Disponibilidade</strong> individual de cada um.
          O bônus é concedido quando o vistoriador mantém disponibilidade em todos os dias do mês.
        </p>
      </div>

      <AdminTable
        data={vistoriadores}
        columns={columns}
        searchPlaceholder="Buscar vistoriador..."
      />

      {/* Modal de edição de bônus */}
      {editando && (
        <AdminModal onClose={() => setEditando(null)} size="sm">
          <AdminModalHeader
            title="Bônus de Disponibilidade"
            subtitle={editando.nome}
            onClose={() => setEditando(null)}
          />
          <AdminModalBody>
            <div className="space-y-4">
              <div className="flex items-start gap-3 p-3 bg-emerald-50 rounded-xl">
                <Gift size={15} className="text-emerald-600 mt-0.5 shrink-0" />
                <p className="text-xs text-emerald-800">
                  O bônus é pago mensalmente se o vistoriador ficar disponível em <strong>todos os dias do mês</strong>.
                  Qualquer registro de indisponibilidade cancela o bônus naquele mês.
                </p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1.5">
                  Valor do bônus (R$)
                </label>
                <input
                  type="number"
                  min="0"
                  step="0.01"
                  value={bonusInput}
                  onChange={(e) => setBonusInput(e.target.value)}
                  className="w-full px-3 py-2.5 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-[#0B7A8F]/20 focus:border-[#0B7A8F]"
                  placeholder="Ex: 150.00"
                />
              </div>
            </div>
          </AdminModalBody>
          <AdminModalFooter>
            <AdminButton variant="outline" onClick={() => setEditando(null)}>
              Cancelar
            </AdminButton>
            <AdminButton
              variant="primary"
              icon={salvou ? <CheckCircle2 size={15} /> : undefined}
              onClick={salvarBonus}
              disabled={salvou || bonusInput.trim() === "" || isNaN(parseFloat(bonusInput))}
            >
              {salvou ? "Salvo!" : "Salvar"}
            </AdminButton>
          </AdminModalFooter>
        </AdminModal>
      )}
    </AdminDashboardLayout>
  )
}

