"use client"

import { cn } from "@/lib/utils"
import { X } from "lucide-react"

interface AdminModalProps {
  children: React.ReactNode
  onClose: () => void
  /** Largura máxima do modal. Padrão: "md" (max-w-2xl) */
  size?: "sm" | "md" | "lg" | "xl"
  /** Altura máxima com scroll. Padrão: "90vh" */
  maxHeight?: string
}

interface AdminModalHeaderProps {
  title: string
  subtitle?: string
  onClose: () => void
}

interface AdminModalBodyProps {
  children: React.ReactNode
  className?: string
}

interface AdminModalFooterProps {
  children: React.ReactNode
  className?: string
}

const sizeMap = {
  sm: "max-w-md",
  md: "max-w-2xl",
  lg: "max-w-3xl",
  xl: "max-w-5xl",
}

export function AdminModal({ children, onClose, size = "md", maxHeight = "90vh" }: AdminModalProps) {
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      {/* Backdrop */}
      <div className="absolute inset-0 bg-black/50" onClick={onClose} />
      {/* Container */}
      <div
        className={cn(
          "relative bg-white rounded-2xl shadow-xl w-full mx-4 overflow-y-scroll",
          sizeMap[size]
        )}
        style={{ maxHeight }}
      >
        {children}
      </div>
    </div>
  )
}

export function AdminModalHeader({ title, subtitle, onClose }: AdminModalHeaderProps) {
  return (
    <div className="sticky top-0 bg-white border-b border-gray-100 px-6 py-4 flex items-center justify-between z-10">
      <div>
        <h2 className="text-lg font-bold text-gray-900">{title}</h2>
        {subtitle && <p className="text-xs text-[#0B7A8F] mt-0.5">{subtitle}</p>}
      </div>
      <button
        type="button"
        onClick={onClose}
        className="p-1.5 rounded-lg text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
      >
        <X size={18} />
      </button>
    </div>
  )
}

export function AdminModalBody({ children, className }: AdminModalBodyProps) {
  return (
    <div className={cn("p-6 space-y-6", className)}>
      {children}
    </div>
  )
}

export function AdminModalFooter({ children, className }: AdminModalFooterProps) {
  return (
    <div className={cn("sticky bottom-0 bg-white border-t border-gray-100 px-6 py-4 flex justify-end gap-3", className)}>
      {children}
    </div>
  )
}

